import React from "react"
import { Link, useNavigate } from 'react-router-dom'


class SignUp extends React.Component {
    constructor(props) {
        super(props)
        this.state = {
            name: "",
            password: ""
        }
    }
    render() {
        return (
            <div>
                <form class className="Form">
                    <input placeholder="Логин" onChange={(e) => this.setState({name: e.target.value})} />
                    <input placeholder="Пароль" onChange={(e) => this.setState({password: e.target.value})} />
                    <Link to="../home">
                        <button onClick={() => this.props.onAdd({name: this.state.name, password: this.state.password})}>Перейти на новую страницу</button>
                    </Link>
                </form>
            </div>
        )
    }
}

export default SignUp
